import { useEvent } from "../hooks/use-event.js";
export function useRowsBetween(rowIdToRowIndexRef, rowByIndex) {
    const rowsBetween = useEvent((startId, endId) => {
        const left = rowIdToRowIndexRef.current.get(startId);
        const right = rowIdToRowIndexRef.current.get(endId);
        if (left == null || right == null)
            return [];
        const start = Math.min(left, right);
        const end = Math.max(left, right);
        const ids = [];
        for (let i = start; i <= end; i++) {
            const row = rowByIndex(i).get();
            if (!row)
                continue;
            ids.push(row.id);
        }
        return ids;
    });
    return rowsBetween;
}
